package com.seaquake6324.civitas.application;
import static org.junit.jupiter.api.Assertions.*;import com.seaquake6324.civitas.application.port.PopulationRepository;import com.seaquake6324.civitas.domain.population.*;import java.util.*;import org.junit.jupiter.api.Test;
class PlayerGenderServiceTest{
 @Test void normalSelectionIsOneTimeWhileAdminOverrideIsExplicit(){Memory repo=new Memory();UUID player=UUID.randomUUID();SelectPlayerGenderService service=new SelectPlayerGenderService();assertTrue(service.select(repo,player,Gender.MALE).success());assertFalse(service.select(repo,player,Gender.FEMALE).success());assertEquals(Gender.MALE,repo.profile(player).orElseThrow().gender());service.adminOverride(repo,player,Gender.FEMALE);assertEquals(Gender.FEMALE,repo.profile(player).orElseThrow().gender());assertEquals(2,repo.profile(player).orElseThrow().revision());}
 private static final class Memory implements PopulationRepository{Map<UUID,PlayerCivitasProfile>p=new HashMap<>();Map<UUID,CitizenRecord>c=new HashMap<>();Map<UUID,Household>h=new HashMap<>();Map<UUID,MarriageProposal>m=new HashMap<>();public Optional<PlayerCivitasProfile>profile(UUID id){return Optional.ofNullable(p.get(id));}public void putProfile(PlayerCivitasProfile v){p.put(v.playerId(),v);}public Optional<CitizenRecord>citizen(UUID id){return Optional.ofNullable(c.get(id));}public Collection<CitizenRecord>citizens(){return c.values();}public void putCitizen(CitizenRecord v){c.put(v.id(),v);}public Optional<Household>household(UUID id){return Optional.ofNullable(h.get(id));}public Collection<Household>households(){return h.values();}public void putHousehold(Household v){h.put(v.id(),v);}public boolean createHousehold(Household v,Map<UUID,Long>e){if(h.containsKey(v.id()))return false;h.put(v.id(),v);return true;}public Optional<Household>householdForPartner(FamilyMemberRef v){return h.values().stream().filter(x->x.partners().contains(v)).findFirst();}public Optional<MarriageProposal>proposal(UUID id){return Optional.ofNullable(m.get(id));}public Optional<MarriageProposal>activeProposalFor(FamilyMemberRef v){return m.values().stream().filter(x->x.status()==MarriageProposal.Status.PENDING&&x.involves(v)).findFirst();}public int proposalCount(){return m.size();}public void putProposal(MarriageProposal v){m.put(v.id(),v);}}
}
